import fs from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { syncSharedSkills } from "./sync-shared-skills.mjs";

export const OPENCODE_PLUGIN_PAYLOAD_PATHS = [
  "plugin",
  "skills",
  "agents",
  "references",
  "workflow-guidance.opencode.json",
  "package.json",
  "tsconfig.json",
];

const thisDir = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(thisDir, "..");
const defaultSourceDir = path.join(repoRoot, "packages", "opencode-adapter");
const defaultBundleOutDir = path.join(repoRoot, "dist", "opencode-plugin");
const defaultInstallDir = path.join(os.homedir(), ".config", "opencode");

async function readJson(jsonPath) {
  return JSON.parse(await fs.readFile(jsonPath, "utf8"));
}

async function pathExists(targetPath) {
  try {
    await fs.access(targetPath);
    return true;
  } catch {
    return false;
  }
}

async function assertPayloadExists(sourceDir, relativePath) {
  const fullPath = path.join(sourceDir, relativePath);
  if (!(await pathExists(fullPath))) {
    throw new Error(`Missing OpenCode plugin payload path: ${relativePath}`);
  }
}

function shouldCopyEntry(sourcePath) {
  return !sourcePath.endsWith(".test.mjs");
}

async function copyDirectoryContents(sourceDir, destinationDir) {
  await fs.mkdir(destinationDir, { recursive: true });
  const entries = await fs.readdir(sourceDir, { withFileTypes: true });
  for (const entry of entries) {
    const sourcePath = path.join(sourceDir, entry.name);
    if (!shouldCopyEntry(sourcePath)) {
      continue;
    }

    const destinationPath = path.join(destinationDir, entry.name);
    if (entry.isDirectory()) {
      await copyDirectoryContents(sourcePath, destinationPath);
      continue;
    }

    await fs.copyFile(sourcePath, destinationPath);
  }
}

async function copyPayloadTree(sourceDir, destinationDir, payloadRelativePaths) {
  await fs.rm(destinationDir, { recursive: true, force: true });
  await fs.mkdir(destinationDir, { recursive: true });

  for (const relativePath of payloadRelativePaths) {
    const sourcePath = path.join(sourceDir, relativePath);
    const destinationPath = path.join(destinationDir, relativePath);
    const sourceStat = await fs.lstat(sourcePath);
    if (sourceStat.isDirectory()) {
      await copyDirectoryContents(sourcePath, destinationPath);
      continue;
    }

    if (!shouldCopyEntry(sourcePath)) {
      continue;
    }

    await fs.mkdir(path.dirname(destinationPath), { recursive: true });
    await fs.copyFile(sourcePath, destinationPath);
  }
}

export async function readOpencodePluginSource({ sourceDir = defaultSourceDir } = {}) {
  await syncSharedSkills();
  const manifestPath = path.join(sourceDir, "package.json");
  const manifest = await readJson(manifestPath);

  for (const relativePath of OPENCODE_PLUGIN_PAYLOAD_PATHS) {
    await assertPayloadExists(sourceDir, relativePath);
  }

  return {
    sourceDir,
    manifestPath,
    manifest,
    name: manifest.name,
    version: manifest.version,
    payloadRelativePaths: [...OPENCODE_PLUGIN_PAYLOAD_PATHS],
  };
}

export async function exportOpencodePluginBundle({ sourceDir = defaultSourceDir, outDir = defaultBundleOutDir } = {}) {
  const plugin = await readOpencodePluginSource({ sourceDir });
  const bundleDir = path.join(outDir, "claw-kit", plugin.version);
  await copyPayloadTree(plugin.sourceDir, bundleDir, plugin.payloadRelativePaths);
  return { ...plugin, outDir, bundleDir };
}

const PLUGIN_DIR_NAME = "claw-kit";

/**
 * opencode scans ~/.config/opencode/plugins/*.ts (or *.js) at the top level only.
 * The actual plugin lives in the `claw-kit/` subdirectory, so we need a shim file
 * at the plugins root that re-exports it.
 */
async function createPluginShim(installDir) {
  const pluginsDir = path.join(installDir, "plugins");
  await fs.mkdir(pluginsDir, { recursive: true });
  const shimPath = path.join(pluginsDir, `${PLUGIN_DIR_NAME}.ts`);
  const content = [
    `// claw-kit OpenCode adapter plugin entry (shim)`,
    `// Auto-generated by install-opencode-plugin — do not edit manually.`,
    `// opencode scans ~/.config/opencode/plugins/*.ts for local plugins.`,
    `// This shim re-exports the actual plugin from the ${PLUGIN_DIR_NAME} subdirectory.`,
    `export { default, ClawKitPlugin } from "./${PLUGIN_DIR_NAME}/plugin/index.ts";`,
    ``,
  ].join("\n");
  await fs.writeFile(shimPath, content, "utf8");
  return shimPath;
}

/**
 * opencode discovers skills ONLY from fixed convention directories:
 *   ~/.config/opencode/skills/<name>/SKILL.md
 *   .opencode/skills/<name>/SKILL.md
 *   .claude/skills/<name>/SKILL.md
 *   ~/.agents/skills/<name>/SKILL.md
 *
 * There is NO `skills.paths` config option (it is not part of the opencode schema and
 * is silently ignored), and the plugin API can register custom `tool`s but NOT skills.
 * So we copy each skill folder into the global opencode skills directory, mirroring how
 * agent files are copied into ~/.config/opencode/agent/. The plugin directory keeps its
 * own skills/ copy as the source asset; this copy is what makes skills discoverable.
 */
async function installSkillsToDiscoveryDir(installDir, sourceDir) {
  const skillsDir = path.join(installDir, "skills");
  const skillsSourceDir = path.join(sourceDir, "skills");
  if (!(await pathExists(skillsSourceDir))) {
    return skillsDir;
  }
  await fs.mkdir(skillsDir, { recursive: true });
  const entries = await fs.readdir(skillsSourceDir, { withFileTypes: true });
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const sourceSkillPath = path.join(skillsSourceDir, entry.name);
    const destSkillPath = path.join(skillsDir, entry.name);
    await copyDirectoryContents(sourceSkillPath, destSkillPath);
  }
  return skillsDir;
}

export async function installOpencodePlugin({ sourceDir = defaultSourceDir, installDir = defaultInstallDir } = {}) {
  const plugin = await readOpencodePluginSource({ sourceDir });

  // Plugin directory: ~/.config/opencode/plugins/claw-kit/
  const pluginDir = path.join(installDir, "plugins", PLUGIN_DIR_NAME);
  await copyPayloadTree(plugin.sourceDir, pluginDir, plugin.payloadRelativePaths);

  // Plugin shim: ~/.config/opencode/plugins/claw-kit.ts
  // opencode only scans *.ts/*.js at the plugins root, not subdirectories.
  const shimPath = await createPluginShim(installDir);

  // Skills discovery copy: opencode only scans convention directories, so copy each
  // skill folder into ~/.config/opencode/skills/ so they appear in available skills.
  const skillsDir = await installSkillsToDiscoveryDir(installDir, sourceDir);

  // Agent files: ~/.config/opencode/agent/
  const agentDir = path.join(installDir, "agent");
  await fs.mkdir(agentDir, { recursive: true });
  const agentSourceDir = path.join(sourceDir, "agents");
  if (await pathExists(agentSourceDir)) {
    const agentFiles = await fs.readdir(agentSourceDir);
    for (const file of agentFiles) {
      if (file.endsWith(".md")) {
        await fs.copyFile(path.join(agentSourceDir, file), path.join(agentDir, file));
      }
    }
  }

  return { ...plugin, installDir, pluginDir, shimPath, skillsDir, agentDir };
}
